/**
 * optic.test.ts — RED+GREEN falsifiable tests for the optical compute kernel.
 * GREEN proves the kernel equals the analytic 2D FFT of (input·mask) [numpy.fft.fft2 ground truth].
 * RED proves it rejects physically-impossible masks (|t|>1 gain, non-finite transmission).
 */
import { test } from 'node:test';
import assert from 'node:assert/strict';
import { opticalMatmul, thinLensMask, OpticalLawError, type Complex, type OpticalMask } from './optic.ts';

